import express from "express";
import cors from "cors";
import { WebSocketServer, WebSocket } from "ws";
import { createServer } from "http";
import { execSync } from "child_process";
import { existsSync } from "fs";
import { getDb } from "./db.js";
import { indexAllCheckpoints } from "./indexer.js";

// ─── Response types ───────────────────────────────────────────────────────────

interface SessionResponse {
  sessionId: string;
  startedAt: string;
  updatedAt: string;
  cwd: string;
  repoRoot: string | null;
  repoName: string | null;
  parentSessionId: string | null;
  childSessionIds: string[];
  gitUserName: string | null;
  gitUserEmail: string | null;
  prompt: string | null;
  summary: string | null;
  keywords: string[];
}

interface EventResponse {
  id: number;
  timestamp: string;
  event: string;
  sessionId: string;
  blocked: boolean;
  data: unknown;
  summary: string | null;
  keywords: string[];
}

interface OverviewResponse {
  sessionId: string;
  summary: string;
  keywords: string[];
  startedAt: string;
  endedAt: string;
}

// ─── Mapping helpers ──────────────────────────────────────────────────────────

function mapSummary(s: {
  intent: string;
  outcome: string;
  learningsRepo: string | null;
  learningsCode: string | null;
  learningsWorkflow: string | null;
  friction: string | null;
  openItems: string | null;
}) {
  return {
    intent: s.intent,
    outcome: s.outcome,
    learningsRepo:     s.learningsRepo     ? (JSON.parse(s.learningsRepo)     as string[]) : [],
    learningsCode:     s.learningsCode     ? (JSON.parse(s.learningsCode)     as Array<{ path: string; finding: string }>) : [],
    learningsWorkflow: s.learningsWorkflow ? (JSON.parse(s.learningsWorkflow) as string[]) : [],
    friction:          s.friction          ? (JSON.parse(s.friction)          as string[]) : [],
    openItems:         s.openItems         ? (JSON.parse(s.openItems)         as string[]) : [],
  };
}


function mapSession(
  s: {
    sessionId: string;
    startedAt: Date;
    updatedAt: Date;
    cwd: string;
    repoRoot: string | null;
    repoName: string | null;
    parentSessionId: string | null;
    gitUserName: string | null;
    gitUserEmail: string | null;
    prompt: string | null;
    summary: string | null;
    keywords: string | null;
  },
  childSessionIds: string[] = [],
): SessionResponse {
  return {
    sessionId: s.sessionId,
    startedAt: s.startedAt.toISOString(),
    updatedAt: s.updatedAt.toISOString(),
    cwd: s.cwd,
    repoRoot: s.repoRoot,
    repoName: s.repoName,
    parentSessionId: s.parentSessionId,
    childSessionIds,
    gitUserName: s.gitUserName,
    gitUserEmail: s.gitUserEmail,
    prompt: s.prompt,
    summary: s.summary,
    keywords: s.keywords ? (JSON.parse(s.keywords) as string[]) : [],
  };
}

function mapEvent(e: {
  id: number;
  timestamp: Date;
  event: string;
  sessionId: string;
  blocked: boolean;
  data: string;
  summary: string | null;
  keywords: string | null;
}): EventResponse {
  let parsedData: unknown;
  try {
    parsedData = JSON.parse(e.data);
  } catch {
    parsedData = e.data;
  }
  return {
    id: e.id,
    timestamp: e.timestamp.toISOString(),
    event: e.event,
    sessionId: e.sessionId,
    blocked: e.blocked,
    data: parsedData,
    summary: e.summary,
    keywords: e.keywords ? (JSON.parse(e.keywords) as string[]) : [],
  };
}

// ─── Server ───────────────────────────────────────────────────────────────────

export async function startServer(dbPath: string, port: number, repoDir?: string): Promise<void> {
  const db = await getDb(dbPath);

  const app = express();
  app.use(cors());
  app.use(express.json());

  // GET /api/sessions
  app.get("/api/sessions", async (_req, res) => {
    try {
      const sessions = await db.session.findMany({
        orderBy: { updatedAt: "desc" },
      });
      // Build parent → children map in memory (no extra queries)
      const childMap = new Map<string, string[]>();
      for (const s of sessions) {
        if (s.parentSessionId) {
          const arr = childMap.get(s.parentSessionId) ?? [];
          arr.push(s.sessionId);
          childMap.set(s.parentSessionId, arr);
        }
      }
      res.json(sessions.map((s) => mapSession(s, childMap.get(s.sessionId) ?? [])));
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // GET /api/sessions/:id
  app.get("/api/sessions/:id", async (req, res) => {
    try {
      const [session, children] = await Promise.all([
        db.session.findUnique({ where: { sessionId: req.params.id } }),
        db.session.findMany({
          where: { parentSessionId: req.params.id },
          select: { sessionId: true },
        }),
      ]);
      if (!session) {
        res.status(404).json({ error: "Session not found" });
        return;
      }
      res.json(mapSession(session, children.map((c) => c.sessionId)));
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // GET /api/sessions/:id/overview
  app.get("/api/sessions/:id/overview", async (req, res) => {
    try {
      const overview = await db.interactionOverview.findUnique({
        where: { sessionId: req.params.id },
      });
      if (!overview) {
        res.status(404).json({ error: "No overview for this session" });
        return;
      }
      const result: OverviewResponse = {
        sessionId: overview.sessionId,
        summary: overview.summary,
        keywords: overview.keywords ? (JSON.parse(overview.keywords) as string[]) : [],
        startedAt: overview.startedAt.toISOString(),
        endedAt: overview.endedAt.toISOString(),
      };
      res.json(result);
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // GET /api/sessions/:id/events
  app.get("/api/sessions/:id/events", async (req, res) => {
    try {
      const events = await db.event.findMany({
